const sdk = window.CueStack;
let chart = null;
let dataPoints = [];
const MAX_POINTS = 100;
let currentSub = null;

// Initialize
setupChart();
switchChannel();
loadTable();

function setupChart() {
  const canvas = document.createElement('canvas');
  document.getElementById('liveChart').appendChild(canvas);
  const ctx = canvas.getContext('2d');
  chart = { ctx, canvas };
  requestAnimationFrame(drawChart);
}

function drawChart() {
  if (!chart) return;
  const { ctx, canvas } = chart;
  canvas.width = canvas.parentElement.clientWidth;
  canvas.height = canvas.parentElement.clientHeight;
  const w = canvas.width, h = canvas.height;
  ctx.fillStyle = '#1e1e1e';
  ctx.fillRect(0, 0, w, h);
  if (dataPoints.length < 2) { requestAnimationFrame(drawChart); return; }
  // Draw temperature line (red)
  ctx.strokeStyle = '#ef4444';
  ctx.lineWidth = 2;
  ctx.beginPath();
  const temps = dataPoints.map(function(d) { return d.temperature; });
  const minT = Math.min.apply(null, temps) - 1, maxT = Math.max.apply(null, temps) + 1;
  dataPoints.forEach(function(d, i) {
    const x = (i / (MAX_POINTS - 1)) * w;
    const y = h - ((d.temperature - minT) / (maxT - minT)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  });
  ctx.stroke();
  // Draw humidity line (blue)
  ctx.strokeStyle = '#3b82f6';
  ctx.beginPath();
  const humids = dataPoints.map(function(d) { return d.humidity; });
  const minH = Math.min.apply(null, humids) - 1, maxH = Math.max.apply(null, humids) + 1;
  dataPoints.forEach(function(d, i) {
    const x = (i / (MAX_POINTS - 1)) * w;
    const y = h - ((d.humidity - minH) / (maxH - minH)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  });
  ctx.stroke();
  // Labels
  ctx.fillStyle = '#ef4444'; ctx.font = '11px monospace';
  ctx.fillText('Temp: ' + (temps[temps.length-1]||0).toFixed(1) + '°C', 8, 14);
  ctx.fillStyle = '#3b82f6';
  ctx.fillText('Humid: ' + (humids[humids.length-1]||0).toFixed(1) + '%', 8, 28);
  requestAnimationFrame(drawChart);
}

function switchChannel() {
  const ch = document.getElementById('channel').value;
  if (currentSub) currentSub();
  dataPoints = [];
  currentSub = sdk.subscribe(ch, function(data, msg) {
    const d = data || msg;
    dataPoints.push(d);
    if (dataPoints.length > MAX_POINTS) dataPoints.shift();
    document.getElementById('liveTemp').textContent = (d.temperature || 0).toFixed(1) + '°C';
    document.getElementById('liveHumid').textContent = (d.humidity || 0).toFixed(1) + '%';
  });
  document.getElementById('liveStatus').textContent = 'Connected';
  document.getElementById('liveStatus').style.background = '#f0fde8';
  document.getElementById('liveStatus').style.color = '#15803d';
}

async function loadTable() {
  const table = document.getElementById('source').value;
  const channel = document.getElementById('channel').value;
  try {
    const data = await sdk.queryEvents({ channel: channel, limit: 50 });
    const events = data.events || [];
    const head = document.getElementById('tableHead');
    const body = document.getElementById('tableBody');
    if (events.length === 0) { body.innerHTML = '<tr><td colspan="4">No data yet</td></tr>'; return; }
    const cols = ['timestamp', 'channel', 'payload'];
    head.innerHTML = cols.map(function(c) { return '<th>' + c + '</th>'; }).join('');
    body.innerHTML = events.map(function(e) { return '<tr>' + cols.map(function(c) { return '<td>' + (e[c] || '') + '</td>'; }).join('') + '</tr>'; }).join('');
  } catch(e) { console.error('Load failed:', e); }
}
